// catalog.ts — Tumaini · TBHOS translation catalog.
//
// Single source of truth for every UI string. Five lanes:
//   sw — Kiswahili (primary, required)
//   en — English (required)
//   ar — Arabic (RTL; partial — assessment cores verified)
//   ru — Russian (partial — UI chrome + selected items)
//   zh — Chinese (Simplified; partial — UI chrome + selected items)
//
// Honesty: when uncertain, OMIT the lane. The t() helper falls back en → sw.
// `verified: { ar: true }` means a clinician or curated source confirmed it.
// Anything else is best-effort and should be reviewed by a native speaker
// before clinical deployment.

export type Lang = 'sw' | 'en' | 'ar' | 'ru' | 'zh'

export const LANGS: readonly Lang[] = ['sw', 'en', 'ar', 'ru', 'zh'] as const

export interface Entry {
  sw: string
  en: string
  ar?: string
  ru?: string
  zh?: string
  verified?: Partial<Record<Lang, boolean>>
}

