  // ─── GAD-7 ───────────────────────────────────────────────────────────────
  'gad7.title': { sw: 'GAD-7 — Tathmini ya wasiwasi', en: 'GAD-7 — Anxiety screen', ar: 'GAD-7 — فحص القلق', verified: { ar: true } },
  'gad7.lead_in': { sw: 'Kwa wiki mbili zilizopita, ni mara ngapi umesumbuliwa na:', en: 'Over the last 2 weeks, how often have you been bothered by:', ar: 'خلال الأسبوعين الماضيين، كم مرة أزعجتك:', verified: { ar: true } },
