  'k10.q2': { sw: 'Umehisi wasiwasi?', en: 'Did you feel nervous?', ar: 'هل شعرت بالعصبية؟', verified: { ar: true } },
  'k10.q3': { sw: 'Wasiwasi mkubwa hadi haukutulizwa na chochote?', en: 'Did you feel so nervous nothing could calm you?', ar: 'هل كان قلقك شديداً؟', verified: { ar: true } },
  'k10.q4': { sw: 'Umehisi kukata tamaa?', en: 'Did you feel hopeless?', ar: 'هل شعرت باليأس؟', verified: { ar: true } },
