  'k10.q9': { sw: 'Huzuni hadi hakuna kinachofariji?', en: 'Did you feel so sad nothing could cheer you?', ar: 'حزن لا يخفف؟', verified: { ar: true } },
  'k10.q10': { sw: 'Umehisi hauna thamani?', en: 'Did you feel worthless?', ar: 'هل شعرت بأنك بلا قيمة؟', verified: { ar: true } },

