  'crafft.q1': { sw: 'Umewahi kupanda gari na dereva aliyekunywa?', en: 'Ridden in a car with a driver who was drinking/using?', ar: 'هل ركبت مع سائق ثمل؟' },
  'crafft.q2': { sw: 'Umetumia pombe/dawa kupumzika au kujisikia bora?', en: 'Used alcohol/drugs to relax or feel better?', ar: 'هل استخدمت لتشعر بالتحسن؟' },
  'crafft.q3': { sw: 'Umetumia pombe/dawa ukiwa peke yako?', en: 'Used alcohol/drugs while alone?', ar: 'هل استخدمت وحدك؟' },
