  // ─── PCL-5 (PTSD) ────────────────────────────────────────────────────────
  'pcl5.title': { sw: 'PCL-5 — Tathmini ya kiwewe (PTSD)', en: 'PCL-5 — PTSD screen', ar: 'PCL-5 — فحص اضطراب ما بعد الصدمة' },
  'pcl5.lead_in': { sw: 'Katika mwezi mmoja uliopita, kwa kiwango gani umehangaika na:', en: 'In the past month, how much have you been bothered by:', ar: 'في الشهر الماضي، إلى أي مدى عانيت من:' },
  'pcl5.q1': { sw: 'Kumbukumbu zinazokurudia za tukio.', en: 'Repeated, disturbing memories of the event.', ar: 'ذكريات متكررة مؤلمة.' },
  'pcl5.q2': { sw: 'Ndoto mbaya za tukio.', en: 'Disturbing dreams of the event.', ar: 'أحلام مزعجة.' },
  'pcl5.q3': { sw: 'Kuhisi kana kwamba tukio linarudia.', en: 'Suddenly feeling/acting as if event were happening again.', ar: 'الشعور بأن الحدث يتكرر.' },
  'pcl5.q4': { sw: 'Kuumia sana ukikumbushwa.', en: 'Feeling very upset when reminded.', ar: 'الانزعاج عند التذكير.' },
  'pcl5.q5': { sw: 'Mwitikio wa mwili — moyo, jasho — ukikumbushwa.', en: 'Strong physical reactions when reminded.', ar: 'ردود فعل جسدية قوية.' },
  'pcl5.q6': { sw: 'Kuepuka kumbukumbu, mawazo, hisia za tukio.', en: 'Avoiding memories, thoughts, or feelings.', ar: 'تجنب الذكريات والمشاعر.' },
  'pcl5.q7': { sw: 'Kuepuka watu, mahali, vinavyokukumbusha.', en: 'Avoiding external reminders.', ar: 'تجنب المذكرات الخارجية.' },
  'pcl5.q8': { sw: 'Shida kukumbuka sehemu muhimu za tukio.', en: 'Trouble remembering important parts of event.', ar: 'صعوبة تذكر الحدث.' },
  'pcl5.q9': { sw: 'Imani hasi kuhusu nafsi yako, watu, dunia.', en: 'Strong negative beliefs about self, others, world.', ar: 'معتقدات سلبية قوية.' },
  'pcl5.q10': { sw: 'Kujilaumu wewe au mtu mwingine.', en: 'Blaming self or others for what happened.', ar: 'لوم النفس أو الآخرين.' },
  'pcl5.q11': { sw: 'Hisia kali hasi — hofu, hasira, hatia, aibu.', en: 'Strong negative feelings — fear, anger, guilt, shame.', ar: 'مشاعر سلبية قوية.' },
  'pcl5.q12': { sw: 'Kupoteza shauku ya shughuli.', en: 'Loss of interest in activities.', ar: 'فقدان الاهتمام.' },
  'pcl5.q13': { sw: 'Kujihisi mbali na watu.', en: 'Feeling distant or cut off from people.', ar: 'الشعور بالبعد عن الآخرين.' },
  'pcl5.q14': { sw: 'Kushindwa kuhisi furaha au upendo.', en: 'Trouble experiencing positive feelings.', ar: 'صعوبة الشعور الإيجابي.' },
  'pcl5.q15': { sw: 'Kuwa na hasira au tabia ya uharibifu.', en: 'Irritable behavior, angry outbursts.', ar: 'سلوك متهيج.' },
  'pcl5.q16': { sw: 'Kuchukua hatari, au kujidhuru.', en: 'Taking too many risks, reckless behavior.', ar: 'سلوك متهور.' },
  'pcl5.q17': { sw: 'Kuwa na taharuki au makini sana.', en: 'Being "super-alert" or watchful.', ar: 'فرط اليقظة.' },
  'pcl5.q18': { sw: 'Kushtushwa kwa urahisi.', en: 'Feeling jumpy or easily startled.', ar: 'سهولة الجفل.' },
  'pcl5.q19': { sw: 'Shida ya kuzingatia.', en: 'Trouble concentrating.', ar: 'صعوبة التركيز.' },
  'pcl5.q20': { sw: 'Shida ya kulala.', en: 'Trouble falling/staying asleep.', ar: 'صعوبة النوم.' },
  'pcl5.scale.0': { sw: 'Hapana kabisa', en: 'Not at all', ar: 'أبداً' },
  'pcl5.scale.1': { sw: 'Kidogo', en: 'A little bit', ar: 'قليلاً' },
  'pcl5.scale.2': { sw: 'Wastani', en: 'Moderately', ar: 'بشكل متوسط' },
  'pcl5.scale.3': { sw: 'Sana', en: 'Quite a bit', ar: 'كثيراً' },
  'pcl5.scale.4': { sw: 'Mno', en: 'Extremely', ar: 'بشدة' },

