  // ─── SDQ (children — 25 stems abridged) ─────────────────────────────────
  'sdq.title': { sw: 'SDQ — Tathmini ya watoto', en: 'SDQ — Strengths and Difficulties', ar: 'SDQ — نقاط القوة والصعوبات' },
  'sdq.q1': { sw: 'Hujali hisia za watu wengine.', en: 'Considerate of other people\'s feelings.', ar: 'مراعٍ لمشاعر الآخرين.' },
  'sdq.q2': { sw: 'Hawezi kukaa kimya, anajongajonga.', en: 'Restless, overactive, cannot stay still.', ar: 'مفرط النشاط.' },
  'sdq.q3': { sw: 'Analalamika maumivu — kichwa, tumbo.', en: 'Complains of headaches, stomachaches.', ar: 'يشكو من الصداع وآلام البطن.' },
  'sdq.q4': { sw: 'Anashiriki kwa urahisi na watoto wengine.', en: 'Shares readily with other children.', ar: 'يشارك بسهولة.' },
  'sdq.q5': { sw: 'Mara nyingi hukasirika.', en: 'Often has temper tantrums.', ar: 'نوبات غضب متكررة.' },
  'sdq.q6': { sw: 'Hupendelea kuwa peke yake.', en: 'Rather solitary, plays alone.', ar: 'يفضل العزلة.' },
  'sdq.q7': { sw: 'Hutii kwa ujumla, hufanya anavyoambiwa.', en: 'Generally obedient.', ar: 'مطيع بشكل عام.' },
  'sdq.q8': { sw: 'Ana wasiwasi mwingi, anaonekana mwenye hofu.', en: 'Many worries, often seems worried.', ar: 'قلق كثيراً.' },
  'sdq.q9': { sw: 'Husaidia mtu aliyeumia, mgonjwa, au msononi.', en: 'Helpful if someone is hurt, upset.', ar: 'متعاون مع المتألمين.' },
  'sdq.q10': { sw: 'Anajongajonga mara kwa mara.', en: 'Constantly fidgeting or squirming.', ar: 'متململ باستمرار.' },
  'sdq.q11': { sw: 'Ana rafiki wa karibu mmoja au zaidi.', en: 'Has at least one good friend.', ar: 'لديه صديق على الأقل.' },
  'sdq.q12': { sw: 'Mara nyingi hupigana, hudhibitiwa na hasira.', en: 'Often fights or bullies others.', ar: 'يتشاجر كثيراً.' },
  'sdq.q13': { sw: 'Anasikitika au ana huzuni mara nyingi.', en: 'Often unhappy, downhearted, tearful.', ar: 'حزين كثيراً.' },

