  'pumzi.intro': { sw: 'Pumua polepole. Kila pumzi ni hatua nyumbani.', en: 'Breathe slowly. Every breath is a step home.', ar: 'تنفّس ببطء. كل نفس خطوة إلى الديار.', ru: 'Дышите медленно. Каждый вдох — шаг домой.', zh: '慢慢呼吸。每一次呼吸都是回家的脚步。' },

  // ─── Roho/Rafiki acknowledgments (composable phrases) ────────────────────
  'rafiki.ack1': { sw: 'Ninakusikia.', en: 'I hear you.', ar: 'أنا أسمعك.', ru: 'Я слышу вас.', zh: '我听到你了。' },
  'rafiki.ack2': { sw: 'Hii ni nzito.', en: 'That is heavy.', ar: 'هذا ثقيل.', ru: 'Это тяжело.', zh: '这很沉重。' },
  'rafiki.ack3': { sw: 'Asante kwa kunishirikisha.', en: 'Thank you for sharing.', ar: 'شكراً لمشاركتي.', ru: 'Спасибо, что поделились.', zh: '谢谢你的分享。' },
  'rafiki.ack4': { sw: 'Tuko pamoja.', en: 'We are together.', ar: 'نحن معاً.', ru: 'Мы вместе.', zh: '我们在一起。' },
  'rafiki.ack5': { sw: 'Pumua polepole.', en: 'Breathe slowly.', ar: 'تنفّس ببطء.', ru: 'Дышите медленно.', zh: '慢慢呼吸。' },
  'rafiki.ack6': { sw: 'Hatua moja kwa wakati.', en: 'One step at a time.', ar: 'خطوة واحدة في كل مرة.', ru: 'Шаг за шагом.', zh: '一步一步来。' },
  'rafiki.ack7': { sw: 'Hauko peke yako.', en: 'You are not alone.', ar: 'لست وحدك.', ru: 'Вы не одни.', zh: '你并不孤单。' },
  'rafiki.ack8': { sw: 'Hisia hizo zinaeleweka.', en: 'Those feelings make sense.', ar: 'هذه المشاعر منطقية.', ru: 'Эти чувства понятны.', zh: '这些感受可以理解。' },
  'rafiki.ack9': { sw: 'Niambie zaidi.', en: 'Tell me more.', ar: 'أخبرني المزيد.', ru: 'Расскажите ещё.', zh: '告诉我更多。' },
  'rafiki.ack10': { sw: 'Niko hapa kwa ajili yako.', en: 'I am here for you.', ar: 'أنا هنا لأجلك.', ru: 'Я здесь для вас.', zh: '我在这里陪你。' },
  'rafiki.transition1': { sw: 'Sasa, hebu tujaribu kitu kidogo.', en: 'Now, let us try something small.', ar: 'الآن، لنجرب شيئاً صغيراً.', ru: 'Теперь попробуем что-то маленькое.', zh: '现在,让我们试一些小事。' },
  'rafiki.transition2': { sw: 'Je, unataka tufanye mazoezi ya kupumua?', en: 'Would you like to try a breath exercise?', ar: 'هل تود تجربة تمرين تنفس؟', ru: 'Хотите попробовать дыхательное упражнение?', zh: '你想试试呼吸练习吗?' },
  'rafiki.transition3': { sw: 'Twende polepole — ungependa kuandika?', en: 'Slowly — would you like to write?', ar: 'ببطء — هل تود الكتابة؟', ru: 'Не спеша — хотите написать?', zh: '慢慢来——想写下来吗?' },
  'rafiki.transition4': { sw: 'Tunaweza kuomba msaada wa daktari?', en: 'May we ask for a clinician\'s help?', ar: 'هل نطلب مساعدة طبيب؟', ru: 'Можем ли мы попросить помощи у врача?', zh: '我们可以请医生帮忙吗?' },
  'rafiki.transition5': { sw: 'Hebu turudi kwenye pumzi.', en: 'Let us return to the breath.', ar: 'لنعد إلى التنفس.', ru: 'Вернёмся к дыханию.', zh: '让我们回到呼吸。' },

