  'karibu.q.why_now': { sw: 'Kwa nini umekuja sasa?', en: 'Why have you come now?', ar: 'لماذا أتيت الآن؟', ru: 'Почему вы пришли сейчас?', zh: '你为什么现在来?' },
  'karibu.q.feelings': { sw: 'Hisia gani zinakusumbua zaidi?', en: 'Which feelings trouble you most?', ar: 'ما المشاعر التي تزعجك أكثر؟', ru: 'Какие чувства беспокоят больше всего?', zh: '哪些感受最困扰你?' },
  'karibu.q.sleep': { sw: 'Unalalaje?', en: 'How do you sleep?', ar: 'كيف تنام؟', ru: 'Как вы спите?', zh: '你睡得怎么样?' },
