  'karibu.q.support': { sw: 'Una watu wa karibu wa kukusaidia?', en: 'Do you have close support?', ar: 'هل لديك دعم قريب؟', ru: 'Есть ли близкая поддержка?', zh: '你有亲近的支持吗?' },
  'karibu.q.work': { sw: 'Unafanya kazi gani?', en: 'What work do you do?', ar: 'ما عملك؟', ru: 'Чем вы занимаетесь?', zh: '你做什么工作?' },
  'karibu.q.faith': { sw: 'Imani inakusaidia?', en: 'Does faith help you?', ar: 'هل يساعدك الإيمان؟', ru: 'Помогает ли вам вера?', zh: '信仰对你有帮助吗?' },
  'karibu.q.alcohol': { sw: 'Unakunywa pombe?', en: 'Do you drink alcohol?', ar: 'هل تشرب الكحول؟', ru: 'Вы употребляете алкоголь?', zh: '你喝酒吗?' },
  'karibu.q.substance': { sw: 'Unatumia vichocheo?', en: 'Do you use substances?', ar: 'هل تستخدم المواد؟', ru: 'Употребляете ли вещества?', zh: '你使用药物吗?' },
  'karibu.q.history': { sw: 'Umewahi kuwa na shida ya akili kabla?', en: 'Have you had mental-health issues before?', ar: 'هل عانيت من مشاكل نفسية سابقاً؟', ru: 'Были ли проблемы с психикой раньше?', zh: '你以前有过心理健康问题吗?' },
  'karibu.q.medication': { sw: 'Unatumia dawa yoyote?', en: 'Are you taking any medication?', ar: 'هل تتناول أي دواء؟', ru: 'Принимаете ли вы лекарства?', zh: '你在服用任何药物吗?' },
  'karibu.q.physical': { sw: 'Una hali za kimwili?', en: 'Any physical conditions?', ar: 'أي حالات جسدية؟', ru: 'Физические состояния?', zh: '有身体状况吗?' },
  'karibu.q.crisis': { sw: 'Umewahi kuwaza kujidhuru?', en: 'Have you ever thought of harming yourself?', ar: 'هل فكرت يوماً في إيذاء نفسك؟', ru: 'Думали ли о самоповреждении?', zh: '你想过自伤吗?' },
  'karibu.q.goals': { sw: 'Unataka kupata nini hapa?', en: 'What do you hope to get here?', ar: 'ماذا تأمل أن تحصل عليه؟', ru: 'Что вы хотите получить здесь?', zh: '你希望在这里得到什么?' },
  'karibu.q.who_help': { sw: 'Unahitaji msaada wa nani?', en: 'Whose help do you need?', ar: 'مساعدة من تحتاج؟', ru: 'Чья помощь нужна?', zh: '你需要谁的帮助?' },
